## Complete Search/Filter Logic Report

I've thoroughly searched the codebase and found all search/filter implementations. Here's a comprehensive breakdown:

---

### 1. ROOT SEARCH IN App.tsx

**File:** `/Users/anotonio.silva/antonio/lol/src/App.tsx`

**Main filtering logic** (lines 290-380):
```typescript
const filtered = useMemo(() => {
  let sections = registrySections;
  if (filterValue === 'commands') {
    sections = sections.filter(
      s => s.title === 'Suggestions' || s.title === 'Commands',
    );
  } else if (filterValue === 'applications') {
    sections = sections.filter(s => s.title === 'Applications');
  }

  const result = query ? searchCommands(query) : sections;

  const filteredResult = query
    ? result
        .map(s => {
          if (filterValue === 'commands') {
            return s.title === 'Suggestions' || s.title === 'Commands'
              ? s
              : {
                  ...s,
                  items: [],
                };
          }
          if (filterValue === 'applications') {
            return s.title === 'Applications'
              ? s
              : {
                  ...s,
                  items: [],
                };
          }
          return s;
        })
        .filter(s => s.items.length > 0)
    : result;

  const allFlatItems = sections.flatMap(s => s.items);
  const favoriteItems = favoriteIds
    .map(id => allFlatItems.find(item => item.id === id))
    .filter((item): item is ListItemData => !!item);

  if (query) {
    const lower = query.toLowerCase();
    const filteredFavs = favoriteItems.filter(
      item =>
        item.title.toLowerCase().includes(lower) ||
        item.subtitle?.toLowerCase().includes(lower),
    );
    if (filteredFavs.length > 0) {
      const favIds = new Set(filteredFavs.map(f => f.id));
      const dedupedSections = filteredResult
        .map(s => ({
          ...s,
          items: s.items.filter(item => !favIds.has(item.id)),
        }))
        .filter(s => s.items.length > 0);
      return [
        {
          title: 'Favorites',
          items: filteredFavs,
        },
        ...dedupedSections,
      ];
    }
    return filteredResult;
  }

  if (favoriteItems.length > 0) {
    const favIds = new Set(favoriteIds);
    const dedupedSections = filteredResult
      .map(s => ({
        ...s,
        items: s.items.filter(item => !favIds.has(item.id)),
      }))
      .filter(s => s.items.length > 0);
    return [
      {
        title: 'Favorites',
        items: favoriteItems,
      },
      ...dedupedSections,
    ];
  }

  return filteredResult;
}, [
  query,
  filterValue,
  favoriteIds,
  registrySections,
]);
```

**Key features:**
- Filters by `filterValue` ('all', 'commands', 'applications')
- Uses `searchCommands(query)` for text search
- Filters favorites separately with `.toLowerCase().includes(lower)`
- Deduplicates favorites from search results

**Query handling** (lines 189, 413-417):
```typescript
const [query, setQuery] = useState('');

const handleQueryChange = useCallback((value: string) => {
  setQuery(value);
  setSelectedIndex(0);
  setActionsOpen(false);
}, []);
```

