### 4. EMOJI PICKER VIEW

**File:** `/Users/anotonio.silva/antonio/lol/src/components/emoji_picker/emoji_picker_view.tsx`

**Filtering logic** (lines 130-148):
```typescript
const filtered = useMemo(() => {
  let emojis = MOCK_EMOJIS;
  if (filterValue !== 'all') {
    emojis = emojis.filter(e => e.category === filterValue);
  }
  if (query) {
    const lower = query.toLowerCase();
    emojis = emojis.filter(
      e =>
        e.name.toLowerCase().includes(lower) ||
        e.keywords.some(k => k.includes(lower)) ||
        e.char === query,
    );
  }
  return emojis;
}, [
  query,
  filterValue,
]);
```

**Section grouping** (lines 150-186):
```typescript
const sections = useMemo(() => {
  const result: EmojiSection[] = [];

  if (!query && filterValue === 'all' && recentEmojis.length > 0) {
    result.push({
      title: 'Recently Used',
      emojis: recentEmojis,
    });
  }

  const grouped = new Map<EmojiCategory, EmojiEntry[]>();
  for (const emoji of filtered) {
    const existing = grouped.get(emoji.category);
    if (existing) {
      existing.push(emoji);
    } else {
      grouped.set(emoji.category, [emoji]);
    }
  }

  for (const cat of EMOJI_CATEGORY_ORDER) {
    const items = grouped.get(cat);
    if (items && items.length > 0) {
      result.push({
        title: EMOJI_CATEGORY_LABELS[cat],
        emojis: items,
      });
    }
  }

  return result;
}, [
  filtered,
  query,
  filterValue,
  recentEmojis,
]);
```

**Search criteria:**
- Name match: `e.name.toLowerCase().includes(lower)`
- Keywords match: `e.keywords.some(k => k.includes(lower))`
- Exact char match: `e.char === query`
- Category filter: `e.category === filterValue`

