    </svg>
  );
}

function loadRecentEmojis(): string[] {
  const stored = storageGet(STORAGE_KEY, isStringArray);
  if (stored) return stored;

  try {
    const legacy = localStorage.getItem('emoji-picker-recent');
    if (legacy) {
